export interface ProtocolTemplate {
  id: string;
  domain: string; // Normalized hostname
  titleSelector: string;
  contentSelector: string;
  removeSelectors?: string[]; // Array of selectors to remove
  createdAt: number;
  updatedAt: number;
}

export interface AppSettings {
  concurrency: number;
  rateLimitPerMinute: number;
  outputDir: string;
  filenamePattern: string; // e.g. "{title}.txt"
}

export interface ExtractedChapter {
  title: string;
  content: string;
  url: string;
}

export interface ExtractionResponse {
  success: boolean;
  data?: ExtractedChapter;
  error?: string;
  matchedProtocol?: string;
}

export interface DiagnosticResult {
  host: string;
  matchedProtocolId?: string;
  titleMatches: number;
  contentMatches: number;
  paragraphCount: number;
  titlePreview: string;
  contentPreview: string;
  error?: string;
}

export interface BatchItem {
  id: string;
  url: string;
  status: 'pending' | 'processing' | 'success' | 'failed';
  result?: ExtractedChapter;
  error?: string;
}

export interface BatchStatus {
  queue: BatchItem[];
  isProcessing: boolean;
  completedCount: number;
  failedCount: number;
  totalCount: number;
}

// Determine API base URL based on the current port.
// In Dev (Vite default port 5173), we hit the backend explicitly at 8787.
// In Prod (Express serving static files at 8787), we use relative paths.
const isDev = typeof window !== 'undefined' && window.location.port !== '8787';
export const API_BASE = isDev ? 'http://localhost:8787' : '';

export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
  const fullUrl = url.startsWith('http') ? url : `${API_BASE}${url}`;

  try {
    const res = await fetch(fullUrl, init);
    const text = await res.text();

    if (!res.ok) {
      let msg = `HTTP ${res.status}`;
      try {
        const j = text ? JSON.parse(text) : null;
        if (j?.error) msg = j.error;
        else if (j?.message) msg = j.message;
      } catch {}
      throw new Error(msg);
    }

    if (!text.trim()) {
       return {} as T; 
    }

    try {
        return JSON.parse(text) as T;
    } catch(e) {
        throw new Error(`Invalid JSON response`);
    }
  } catch (error: any) {
    if (error.message === 'Failed to fetch') {
      throw new Error('Connection to backend failed. Check port 8787.');
    }
    throw error;
  }
}

import { promises as fsp } from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import type { AppSettings, ProtocolTemplate } from '../types.ts';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const DATA_DIR = path.join(__dirname, '..', 'data');
const TEMPLATES_FILE = path.join(DATA_DIR, 'templates.json');
const SETTINGS_FILE = path.join(DATA_DIR, 'settings.json');

const DEFAULT_SETTINGS: AppSettings = {
  concurrency: 2,
  rateLimitPerMinute: 30,
  outputDir: './output',
  filenamePattern: '{title}.txt',
};

async function ensureDir(dir: string) {
  try {
    await fsp.mkdir(dir, { recursive: true });
  } catch (e) {
    // ignore if exists
  }
}

async function readJson<T>(file: string, defaultVal: T): Promise<T> {
  try {
    const data = await fsp.readFile(file, 'utf-8');
    if (!data.trim()) return defaultVal;
    return JSON.parse(data);
  } catch (e) {
    return defaultVal;
  }
}

async function writeJson(file: string, data: any) {
  await ensureDir(path.dirname(file));
  await fsp.writeFile(file, JSON.stringify(data, null, 2), 'utf-8');
}

export async function initStorage() {
  await ensureDir(DATA_DIR);
}

export async function getSettings(): Promise<AppSettings> {
  const loaded = await readJson<Partial<AppSettings>>(SETTINGS_FILE, {});
  return { ...DEFAULT_SETTINGS, ...loaded };
}

export async function saveSettings(settings: AppSettings) {
  await writeJson(SETTINGS_FILE, settings);
}

export async function getTemplates(): Promise<ProtocolTemplate[]> {
  return readJson<ProtocolTemplate[]>(TEMPLATES_FILE, []);
}

export async function saveTemplates(templates: ProtocolTemplate[]) {
  await writeJson(TEMPLATES_FILE, templates);
}

import { URL } from 'url';

export function normalizeHost(input: string): string {
  if (!input) return '';
  let host = input.toLowerCase().trim();

  // If it doesn't have protocol, might be just a domain, try adding https:// to parse
  if (!host.startsWith('http://') && !host.startsWith('https://')) {
    // Check if it looks like a url "example.com/foo"
    if (host.includes('/')) {
       host = 'https://' + host;
    }
  }

  try {
    // Try parsing as URL
    const urlObj = new URL(host);
    host = urlObj.hostname;
  } catch (e) {
    // If fail, assume it is just a domain string already
  }

  // Strip www.
  if (host.startsWith('www.')) {
    host = host.substring(4);
  }

  return host;
}

import * as cheerio from 'cheerio';
import { chromium } from 'playwright';
import { normalizeHost } from './domain.ts';
import type { ProtocolTemplate, DiagnosticResult, AppSettings } from '../types.ts';

// Standardized cleanup function
function cleanText(text: string): string {
  if (!text) return '';
  // Normalize whitespace, collapse multiple newlines
  let t = text.replace(/\s+/g, ' ').trim(); 
  // Restore basic paragraph breaks if they were squashed? 
  // Actually, cheerio extraction usually gets text block by block.
  // The prompt asks to: Trim whitespace, normalize CRLF to LF, collapse 3+ newlines to 2.

  // Actually the text comes from blocks. We will join blocks with \n\n. 
  // So here we just trim the content of a single paragraph.
  return t;
}

function postProcessBody(body: string): string {
    return body
        .replace(/\r\n/g, '\n') // CRLF -> LF
        .replace(/\n{3,}/g, '\n\n') // Collapse 3+ newlines
        .trim();
}

export async function fetchHtml(url: string, waitForSelector?: string): Promise<string> {
    // Try basic fetch first if no wait required
    if (!waitForSelector) {
        try {
            const res = await fetch(url, { 
                headers: { 
                    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36' 
                } 
            });
            if (res.status === 429 || res.status === 503) {
                throw new Error(`Blocked: ${res.status}`);
            }
            if (!res.ok) throw new Error(`HTTP ${res.status}`);
            return await res.text();
        } catch (e: any) {
            if (e.message.includes('Blocked')) throw e;
            console.log(`Fetch failed for ${url}, falling back to Playwright: ${e.message}`);
        }
    }

    // Playwright fallback
    const browser = await chromium.launch();
    try {
        const page = await browser.newPage();
        await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
        if (waitForSelector) {
            try { await page.waitForSelector(waitForSelector, { timeout: 5000 }); } catch {}
        }
        const content = await page.content();
        return content;
    } finally {
        await browser.close();
    }
}

export function findProtocol(url: string, templates: ProtocolTemplate[]): ProtocolTemplate | undefined {
    const host = normalizeHost(url);
    return templates.find(t => {
        const tHost = normalizeHost(t.domain);
        return host === tHost || host.endsWith('.' + tHost);
    });
}

export async function extract(url: string, templates: ProtocolTemplate[]) {
    const protocol = findProtocol(url, templates);
    const html = await fetchHtml(url, protocol ? protocol.contentSelector : undefined);
    const $ = cheerio.load(html);

    let title = '';
    let body = '';

    if (protocol) {
        // 1. Root
        const $root = $(protocol.contentSelector).first();
        if ($root.length === 0) {
            throw new Error(`Content selector '${protocol.contentSelector}' matched 0 elements.`);
        }

        // 2. Cleanup
        // Standard removals
        $root.find('script, style, iframe, noscript').remove();
        $root.find('div[id^="pf-"]').remove(); // Ad blocks logic per prompt

        // Custom removals
        if (protocol.removeSelectors) {
            protocol.removeSelectors.forEach(sel => $root.find(sel).remove());
        }

        // 3. Title
        const $title = $(protocol.titleSelector).first();
        title = cleanText($title.text());

        // 4. Body Paragraphs
        const paras: string[] = [];
        $root.find('p').each((_, el) => {
            const t = cleanText($(el).text());
            if (t) paras.push(t);
        });

        // 5. Remove dup title
        if (paras.length > 0 && paras[0] === title) {
            paras.shift();
        }

        // Fallback if no P tags
        if (paras.length === 0) {
            const raw = cleanText($root.text());
            // Attempt to remove title from raw text if it starts with it
            if (raw.startsWith(title)) {
                body = raw.substring(title.length).trim();
            } else {
                body = raw;
            }
        } else {
            body = paras.join('\n\n');
        }

    } else {
        // Heuristic / Auto Mode fallback
        // Very basic fallback since prompt emphasizes Protocols
        const titleEl = $('h1').first();
        title = cleanText(titleEl.text());
        $('script, style, iframe').remove();
        const paras: string[] = [];
        $('p').each((_, el) => {
             const t = cleanText($(el).text());
             if (t && t.length > 20) paras.push(t);
        });
        body = paras.join('\n\n');
        if (!body) throw new Error("No protocol found and auto-extraction failed.");
    }

    return {
        title,
        content: postProcessBody(body),
        url,
        matchedProtocol: protocol?.domain
    };
}

export async function runDiagnostics(
    url: string, 
    domain: string, 
    titleSelector: string, 
    contentSelector: string, 
    removalSelectors: string[] = []
): Promise<DiagnosticResult> {
    const html = await fetchHtml(url);
    const $ = cheerio.load(html);
    const host = normalizeHost(url);

    const $root = $(contentSelector).first();
    const contentMatches = $(contentSelector).length;

    // Virtual cleanup for preview
    const $clone = $root.clone();
    $clone.find('script, style, iframe, noscript').remove();
    $clone.find('div[id^="pf-"]').remove();
    removalSelectors.forEach(s => {
        if(s.trim()) $clone.find(s).remove();
    });

    const $title = $(titleSelector).first();
    const titleMatches = $(titleSelector).length;
    const titleText = cleanText($title.text());

    let pCount = 0;
    const paras: string[] = [];
    $clone.find('p').each((_, el) => {
        const t = cleanText($(el).text());
        if (t) {
            paras.push(t);
            pCount++;
        }
    });

    let bodyPreview = '';
    if (paras.length > 0) {
        if (paras[0] === titleText) paras.shift();
        bodyPreview = paras.join('\n\n');
    } else {
        bodyPreview = cleanText($clone.text());
    }

    return {
        host,
        titleMatches,
        contentMatches,
        paragraphCount: pCount,
        titlePreview: titleText.substring(0, 120),
        contentPreview: bodyPreview.substring(0, 120),
    };
}

import type { BatchItem, BatchStatus } from '../types.ts';
import * as extractor from './extractor.ts';
import * as storage from './storage.ts';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';

let queue: BatchItem[] = [];
let isProcessing = false;
let activeWorkers = 0;
let shouldStop = false;

// Token bucket for rate limiting
let tokens = 0;
let lastRefill = Date.now();

export function getStatus(): BatchStatus {
    const completed = queue.filter(i => i.status === 'success').length;
    const failed = queue.filter(i => i.status === 'failed').length;
    return {
        queue,
        isProcessing,
        completedCount: completed,
        failedCount: failed,
        totalCount: queue.length
    };
}

export function addItems(urls: string[]) {
    const newItems = urls.map(url => ({
        id: Math.random().toString(36).substring(2, 9),
        url: url.trim(),
        status: 'pending' as const
    }));
    queue.push(...newItems);
}

export function clearQueue() {
    if (!isProcessing) {
        queue = [];
    }
}

export async function startProcessing() {
    if (isProcessing) return;
    shouldStop = false;
    isProcessing = true;

    const settings = await storage.getSettings();
    const maxConcurrency = settings.concurrency || 1;

    // Init tokens
    tokens = settings.rateLimitPerMinute; 
    lastRefill = Date.now();

    // Main loop
    while (!shouldStop) {
        // Refill tokens
        const now = Date.now();
        const elapsed = now - lastRefill;
        if (elapsed > 60000) {
            tokens = settings.rateLimitPerMinute;
            lastRefill = now;
        }

        // Check completion
        const pending = queue.find(i => i.status === 'pending');
        if (!pending && activeWorkers === 0) {
            isProcessing = false;
            break;
        }

        // Spawn worker if allowed
        if (pending && activeWorkers < maxConcurrency && tokens > 0) {
            tokens--;
            activeWorkers++;
            processItem(pending).finally(() => {
                activeWorkers--;
            });
        }

        // Wait a bit before next loop tick
        await new Promise(r => setTimeout(r, 200));
    }

    isProcessing = false;
}

export function stopProcessing() {
    shouldStop = true;
}

async function processItem(item: BatchItem) {
    item.status = 'processing';
    try {
        const templates = await storage.getTemplates();
        const result = await extractor.extract(item.url, templates);
        item.result = result;
        item.status = 'success';
    } catch (e: any) {
        item.status = 'failed';
        item.error = e.message;
        console.error(`Failed ${item.url}:`, e);
    }
}

export async function createBatchZip() {
    const zip = new AdmZip();
    const successItems = queue.filter(i => i.status === 'success' && i.result);

    // Add text files
    successItems.forEach(item => {
        if (item.result) {
            const safeTitle = sanitize(item.result.title).substring(0, 100);
            const content = `${item.result.title}\n\n${item.result.content}`;
            zip.addFile(`${safeTitle}.txt`, Buffer.from(content, 'utf8'));
        }
    });

    // Add manifest
    const manifest = {
        generatedAt: new Date().toISOString(),
        total: successItems.length,
        items: successItems.map(i => ({
            url: i.url,
            title: i.result?.title,
            filename: `${sanitize(i.result?.title || '')}.txt`
        }))
    };
    zip.addFile('manifest.json', Buffer.from(JSON.stringify(manifest, null, 2), 'utf8'));

    return zip.toBuffer();
}

import express from 'express';
import cors from 'cors';
import * as storage from './storage.ts';
import * as extractor from './extractor.ts';
import * as queue from './queue.ts';
import { normalizeHost } from './domain.ts';

const app = express();
const PORT = process.env.PORT || 8787;

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Init
storage.initStorage().catch(console.error);

// Async Wrapper
const asyncHandler = (fn: any) => (req: any, res: any, next: any) => {
    Promise.resolve(fn(req, res, next)).catch(next);
};

// --- ROUTES ---

app.get('/api/health', (req, res) => res.json({ status: 'ok', version: '2.0.0' }));

// Settings
app.get('/api/settings', asyncHandler(async (req: any, res: any) => {
    res.json(await storage.getSettings());
}));

app.post('/api/settings', asyncHandler(async (req: any, res: any) => {
    await storage.saveSettings(req.body);
    res.json({ success: true });
}));

// Templates
app.get('/api/templates', asyncHandler(async (req: any, res: any) => {
    res.json(await storage.getTemplates());
}));

app.post('/api/templates', asyncHandler(async (req: any, res: any) => {
    const input = req.body;
    const templates = await storage.getTemplates();

    const now = Date.now();
    const doc = {
        id: input.id || Math.random().toString(36).substring(2, 9),
        domain: normalizeHost(input.domain),
        titleSelector: input.titleSelector,
        contentSelector: input.contentSelector,
        removeSelectors: input.removeSelectors || [],
        createdAt: input.createdAt || now,
        updatedAt: now
    };

    const idx = templates.findIndex(t => t.id === doc.id);
    if (idx >= 0) templates[idx] = doc;
    else templates.push(doc);

    await storage.saveTemplates(templates);
    res.json({ success: true, doc });
}));

app.delete('/api/templates/:id', asyncHandler(async (req: any, res: any) => {
    let templates = await storage.getTemplates();
    templates = templates.filter(t => t.id !== req.params.id);
    await storage.saveTemplates(templates);
    res.json({ success: true });
}));

// Extraction
app.post('/api/extract', asyncHandler(async (req: any, res: any) => {
    const { url } = req.body;
    if (!url) throw new Error("URL required");
    const templates = await storage.getTemplates();
    const result = await extractor.extract(url, templates);
    res.json({ success: true, data: result });
}));

app.post('/api/protocol/diagnostics', asyncHandler(async (req: any, res: any) => {
    const { url, domain, titleSelector, contentSelector, removeSelectors } = req.body;
    const result = await extractor.runDiagnostics(url, domain, titleSelector, contentSelector, removeSelectors);
    res.json(result);
}));

// Batch
app.get('/api/batch/status', (req, res) => {
    res.json(queue.getStatus());
});

app.post('/api/batch/add', (req, res) => {
    const { urls } = req.body; // Expect array of strings
    if (Array.isArray(urls)) {
        queue.addItems(urls);
    }
    res.json({ success: true });
});

app.post('/api/batch/start', asyncHandler(async (req: any, res: any) => {
    queue.startProcessing();
    res.json({ success: true });
}));

app.post('/api/batch/stop', (req, res) => {
    queue.stopProcessing();
    res.json({ success: true });
});

app.post('/api/batch/clear', (req, res) => {
    queue.clearQueue();
    res.json({ success: true });
});

app.get('/api/batch/download', asyncHandler(async (req: any, res: any) => {
    const buffer = await queue.createBatchZip();
    res.set('Content-Type', 'application/zip');
    res.set('Content-Disposition', 'attachment; filename=ronin_batch.zip');
    res.send(buffer);
}));

// Error Handler
app.use((err: any, req: any, res: any, next: any) => {
    console.error(err);
    res.status(500).json({ error: err.message });
});

app.listen(PORT, () => {
    console.log(`RoninClip Backend running on port ${PORT}`);
});

