import React, { useState } from 'react';
import { Play, Copy, Download, Loader2, AlertCircle, Terminal, FileText } from 'lucide-react';
import { ExtractedChapter, ExtractionResponse } from '../types';
import { fetchJson } from '../src/lib/http';

export default function SingleExtract() {
  const [url, setUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<ExtractedChapter | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleExtract = async () => {
    if (!url) return;
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const resp = await fetchJson<ExtractionResponse>('/api/extract', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (resp.success && resp.data) {
          setResult(resp.data);
      } else {
          setError(resp.error || 'Unknown error');
      }
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const copy = (text: string) => navigator.clipboard.writeText(text);

  const download = () => {
    if (!result) return;
    const blob = new Blob([`${result.title}\n\n${result.content}`], {type: 'text/plain'});
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = `${result.title.replace(/[^a-z0-9]/gi, '_')}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase">Single Extraction</h2>
        <p className="text-steel font-mono text-sm">Target singular web entity for processing.</p>
      </div>

      <div className="bg-armor border border-white/10 p-1 flex">
        <div className="flex-1 bg-plate relative group">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Terminal className="h-4 w-4 text-steel" />
            </div>
            <input
              type="url"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              placeholder="ENTER TARGET URL..."
              className="w-full bg-transparent text-white p-4 pl-12 focus:outline-none font-mono text-sm"
              onKeyDown={e => e.key === 'Enter' && handleExtract()}
            />
        </div>
        <button
            onClick={handleExtract}
            disabled={loading || !url}
            className="bg-katana hover:bg-red-600 text-black px-8 font-bold uppercase tracking-widest disabled:opacity-50 transition-all flex items-center gap-2"
        >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5 fill-current" />}
            Execute
        </button>
      </div>

      {error && (
        <div className="bg-red-950/30 text-red-400 p-4 border border-red-900/50 flex items-center gap-3 font-mono text-sm">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>&gt; ERR: {error}</p>
        </div>
      )}

      {result && (
        <div className="bg-armor border border-white/10 relative flex flex-col h-[600px]">
          <div className="bg-black/40 px-6 py-4 border-b border-white/5 flex justify-between items-center backdrop-blur-sm">
            <div>
              <h3 className="font-bold text-white text-lg tracking-wide">{result.title}</h3>
              <p className="text-[10px] text-katana font-mono uppercase tracking-wider truncate max-w-md">{result.url}</p>
            </div>
            <div className="flex gap-2">
              <button onClick={() => copy(result.title)} className="px-3 py-1 bg-white/5 hover:bg-white/10 text-xs font-mono uppercase border border-white/10">Copy Title</button>
              <button onClick={() => copy(result.content)} className="px-3 py-1 bg-white/5 hover:bg-white/10 text-xs font-mono uppercase border border-white/10">Copy Body</button>
              <button onClick={download} className="px-3 py-1 bg-katana hover:bg-red-600 text-black text-xs font-mono uppercase font-bold flex items-center gap-2"><Download className="w-3 h-3"/> TXT</button>
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
            <pre className="whitespace-pre-wrap font-serif text-lg leading-relaxed text-gray-300 font-light max-w-3xl mx-auto">
              {result.content}
            </pre>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Play, Pause, Download, Loader2, CheckCircle, XCircle, List, TerminalSquare } from 'lucide-react';
import { BatchStatus } from '../types';
import { fetchJson, API_BASE } from '../src/lib/http';

export default function BatchExtract() {
  const [urls, setUrls] = useState('');
  const [status, setStatus] = useState<BatchStatus>({ queue: [], isProcessing: false, completedCount: 0, failedCount: 0, totalCount: 0 });

  useEffect(() => {
    fetchStatus();
    const interval = setInterval(fetchStatus, 1000);
    return () => clearInterval(interval);
  }, []);

  const fetchStatus = async () => {
      try {
          const data = await fetchJson<BatchStatus>('/api/batch/status');
          setStatus(data);
      } catch (e) { console.error(e); }
  };

  const addToQueue = async () => {
    const list = urls.split('\n').map(u => u.trim()).filter(u => u);
    if (!list.length) return;
    await fetchJson('/api/batch/add', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify({ urls: list })
    });
    setUrls('');
    fetchStatus();
  };

  const toggleProcessing = async () => {
      const endpoint = status.isProcessing ? '/api/batch/stop' : '/api/batch/start';
      await fetchJson(endpoint, { method: 'POST' });
      fetchStatus();
  };

  const clear = async () => {
      await fetchJson('/api/batch/clear', { method: 'POST' });
      fetchStatus();
  };

  const download = () => {
      window.location.href = `${API_BASE}/api/batch/download`;
  };

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-end border-b border-white/10 pb-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
             <List className="text-katana" /> Batch Processor
          </h2>
          <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; AWAITING INPUT STREAM</p>
        </div>
        <div className="flex gap-3">
           <button onClick={toggleProcessing} disabled={status.queue.length === 0} className={`px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all border ${status.isProcessing ? 'border-yellow-500 text-yellow-500 hover:bg-yellow-500/10' : 'bg-katana text-black border-katana hover:bg-red-600'}`}>
               {status.isProcessing ? <><Pause className="w-4 h-4" /> Pause</> : <><Play className="w-4 h-4 fill-current" /> Engage</>}
           </button>
           <button onClick={download} disabled={status.completedCount === 0} className="border border-white/20 text-white hover:border-katana hover:text-katana px-6 py-2 uppercase text-xs font-bold tracking-widest flex items-center gap-2 transition-all disabled:opacity-30">
             <Download className="w-4 h-4" /> Archive
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1 min-h-0">
        <div className="bg-armor border border-white/10 p-1 flex flex-col h-full">
           <textarea
            className="flex-1 w-full p-4 bg-void text-steel focus:outline-none focus:bg-black font-mono text-xs resize-none placeholder:text-gray-800"
            placeholder="PASTE URLS [ONE PER LINE]..."
            value={urls}
            onChange={e => setUrls(e.target.value)}
          />
          <button onClick={addToQueue} className="w-full bg-white/5 text-white py-3 hover:bg-katana hover:text-black border-t border-white/10 font-mono text-xs uppercase tracking-widest flex justify-center items-center gap-2 transition-colors">
            <Plus className="w-4 h-4" /> Add to Queue
          </button>
        </div>

        <div className="lg:col-span-2 bg-armor border border-white/10 flex flex-col min-h-0">
           <div className="p-3 bg-white/5 border-b border-white/5 flex justify-between items-center">
               <div className="flex gap-4 font-mono text-xs">
                   <span className="text-steel">TOTAL: <span className="text-white">{status.totalCount}</span></span>
                   <span className="text-steel">OK: <span className="text-green-500">{status.completedCount}</span></span>
                   <span className="text-steel">FAIL: <span className="text-katana">{status.failedCount}</span></span>
               </div>
               <button onClick={clear} className="text-steel hover:text-katana"><Trash2 className="w-4 h-4"/></button>
           </div>

           <div className="flex-1 overflow-y-auto custom-scrollbar">
               <table className="w-full text-left font-mono text-xs">
                   <thead className="text-steel bg-black/20 sticky top-0">
                       <tr>
                           <th className="px-4 py-2">State</th>
                           <th className="px-4 py-2">Payload</th>
                       </tr>
                   </thead>
                   <tbody className="divide-y divide-white/5">
                       {status.queue.map(item => (
                           <tr key={item.id} className="hover:bg-white/5">
                               <td className="px-4 py-2 w-32">
                                   {item.status === 'pending' && <span className="text-steel">WAITING</span>}
                                   {item.status === 'processing' && <span className="text-blue-400 flex gap-2 items-center"><Loader2 className="w-3 h-3 animate-spin"/> RUNNING</span>}
                                   {item.status === 'success' && <span className="text-green-500 flex gap-2 items-center"><CheckCircle className="w-3 h-3"/> OK</span>}
                                   {item.status === 'failed' && <span className="text-katana flex gap-2 items-center"><XCircle className="w-3 h-3"/> FAIL</span>}
                               </td>
                               <td className="px-4 py-2 truncate max-w-xs">
                                   <div className="text-white truncate">{item.result?.title || item.url}</div>
                                   {item.error && <div className="text-red-500">{item.error}</div>}
                               </td>
                           </tr>
                       ))}
                   </tbody>
               </table>
               {status.queue.length === 0 && (
                   <div className="flex flex-col items-center justify-center h-full opacity-20 gap-4">
                       <TerminalSquare className="w-12 h-12"/>
                       <span className="font-mono text-xs tracking-widest">BUFFER EMPTY</span>
                   </div>
               )}
           </div>
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { ProtocolTemplate, DiagnosticResult } from '../types';
import { fetchJson } from '../src/lib/http';
import { Plus, Trash, Save, LayoutTemplate, ScanLine, Play, AlertTriangle } from 'lucide-react';

export default function Protocols() {
  const [protocols, setProtocols] = useState<ProtocolTemplate[]>([]);
  const [editing, setEditing] = useState<Partial<ProtocolTemplate>>({});
  const [testUrl, setTestUrl] = useState('');
  const [diag, setDiag] = useState<DiagnosticResult | null>(null);

  useEffect(() => {
    loadProtocols();
  }, []);

  const loadProtocols = () => fetchJson<ProtocolTemplate[]>('/api/templates').then(setProtocols);

  const save = async () => {
      if (!editing.domain || !editing.titleSelector || !editing.contentSelector) return;
      await fetchJson('/api/templates', {
          method: 'POST',
          headers: {'Content-Type': 'application/json'},
          body: JSON.stringify(editing)
      });
      setEditing({});
      loadProtocols();
  };

  const remove = async (id: string) => {
      await fetchJson(`/api/templates/${id}`, { method: 'DELETE' });
      loadProtocols();
      if (editing.id === id) setEditing({});
  };

  const runDiagnostics = async () => {
      if (!testUrl || !editing.titleSelector || !editing.contentSelector) return;
      setDiag(null);
      try {
          const res = await fetchJson<DiagnosticResult>('/api/protocol/diagnostics', {
              method: 'POST',
              headers: {'Content-Type': 'application/json'},
              body: JSON.stringify({
                  url: testUrl,
                  domain: editing.domain,
                  titleSelector: editing.titleSelector,
                  contentSelector: editing.contentSelector,
                  removeSelectors: editing.removeSelectors
              })
          });
          setDiag(res);
      } catch (e: any) {
          setDiag({ error: e.message } as DiagnosticResult);
      }
  };

  return (
    <div className="h-full flex flex-col space-y-6 animate-in fade-in duration-500">
      <div className="flex justify-between items-center border-b border-white/10 pb-4">
        <div>
           <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
              <ScanLine className="text-katana" /> Protocols
           </h2>
           <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; DOMAIN SPECIFIC SELECTOR CONFIGURATION</p>
        </div>
        <button onClick={() => setEditing({ id: '', removeSelectors: [] })} className="bg-white/10 hover:bg-katana hover:text-black text-white px-4 py-2 text-xs font-bold uppercase tracking-widest flex items-center gap-2 transition-all">
           <Plus className="w-4 h-4" /> Initialize New
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 flex-1 min-h-0">
        <div className="bg-armor border border-white/10 flex flex-col">
           <div className="p-3 bg-white/5 border-b border-white/5 font-mono text-xs font-bold text-steel uppercase tracking-wider">Stored Domains</div>
           <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-2">
             {protocols.map(p => (
               <div key={p.id} onClick={() => setEditing(p)} className={`p-4 border border-white/5 bg-void hover:border-katana/50 cursor-pointer group ${editing.id === p.id ? 'border-katana bg-white/5' : ''}`}>
                 <div className="flex justify-between items-start">
                    <div>
                        <div className="font-bold text-white font-mono">{p.domain}</div>
                        <div className="text-[10px] text-steel mt-1 font-mono">{p.contentSelector}</div>
                    </div>
                    <button onClick={(e) => { e.stopPropagation(); remove(p.id); }} className="text-steel hover:text-katana p-1 opacity-0 group-hover:opacity-100"><Trash className="w-3 h-3"/></button>
                 </div>
               </div>
             ))}
           </div>
        </div>

        <div className="lg:col-span-2 bg-armor border border-white/10 p-8 overflow-y-auto custom-scrollbar relative">
          {editing.domain !== undefined ? (
            <div className="space-y-8">
              <div className="flex items-center justify-between border-b border-white/10 pb-4">
                 <h3 className="text-lg font-bold text-white uppercase tracking-widest">Configuration</h3>
                 <span className="text-xs font-mono text-katana animate-pulse">EDIT MODE</span>
              </div>

              <div className="grid grid-cols-1 gap-6">
                <div className="space-y-2">
                  <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Domain (Hostname)</label>
                  <input 
                    type="text" 
                    value={editing.domain || ''} 
                    onChange={e => setEditing({...editing, domain: e.target.value})}
                    className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono text-sm"
                    placeholder="example.com"
                  />
                </div>

                <div className="p-6 bg-black/40 border border-white/5 space-y-4">
                  <h4 className="text-xs font-bold text-katana uppercase tracking-wider">Diagnostics</h4>
                  <div className="flex gap-2">
                     <input 
                       type="text" 
                       placeholder="Test URL" 
                       value={testUrl}
                       onChange={e => setTestUrl(e.target.value)}
                       className="flex-1 bg-void border border-white/10 p-2 text-white text-xs font-mono focus:border-katana focus:outline-none"
                     />
                     <button onClick={runDiagnostics} className="bg-white/5 border border-white/10 text-white hover:bg-white/10 px-4 py-2 text-xs font-mono uppercase flex items-center gap-2">
                        <Play className="w-3 h-3" /> Test
                     </button>
                  </div>
                  {diag && (
                      <div className="text-xs font-mono bg-black p-4 border-l-2 border-katana space-y-2">
                          {diag.error ? <div className="text-red-500">ERR: {diag.error}</div> : (
                              <>
                                <div className="grid grid-cols-2 gap-4 border-b border-white/10 pb-2 mb-2">
                                    <div>HOST: <span className="text-white">{diag.host}</span></div>
                                    <div>TITLE MATCH: <span className={diag.titleMatches ? "text-green-500" : "text-red-500"}>{diag.titleMatches}</span></div>
                                    <div>CONTENT MATCH: <span className={diag.contentMatches ? "text-green-500" : "text-red-500"}>{diag.contentMatches}</span></div>
                                    <div>PARAGRAPHS: <span className="text-white">{diag.paragraphCount}</span></div>
                                </div>
                                <div>
                                    <div className="text-steel mb-1">TITLE PREVIEW &gt;</div>
                                    <div className="text-white mb-2">{diag.titlePreview || "NONE"}</div>
                                    <div className="text-steel mb-1">BODY PREVIEW &gt;</div>
                                    <div className="text-white opacity-70 whitespace-pre-wrap line-clamp-4">{diag.contentPreview || "NONE"}</div>
                                </div>
                              </>
                          )}
                      </div>
                  )}
                </div>

                <div className="grid grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Title Selector</label>
                    <input 
                      type="text" 
                      value={editing.titleSelector || ''} 
                      onChange={e => setEditing({...editing, titleSelector: e.target.value})}
                      placeholder="h1"
                      className="w-full bg-plate border border-white/10 p-3 text-katana focus:border-katana focus:outline-none font-mono text-sm"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Content Selector (Root)</label>
                    <input 
                      type="text" 
                      value={editing.contentSelector || ''} 
                      onChange={e => setEditing({...editing, contentSelector: e.target.value})}
                      placeholder="#content"
                      className="w-full bg-plate border border-white/10 p-3 text-katana focus:border-katana focus:outline-none font-mono text-sm"
                    />
                  </div>
                </div>

                <div className="space-y-2">
                   <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Removal Selectors (CSV)</label>
                   <input 
                      type="text" 
                      value={editing.removeSelectors?.join(', ') || ''} 
                      onChange={e => setEditing({...editing, removeSelectors: e.target.value.split(',').map(s => s.trim())})}
                      placeholder=".ad, .share"
                      className="w-full bg-plate border border-white/10 p-3 text-red-400 focus:border-katana focus:outline-none font-mono text-sm"
                    />
                </div>

                <div className="pt-6 border-t border-white/10 flex justify-end">
                   <button onClick={save} className="px-6 py-2 bg-katana text-black hover:bg-red-500 text-xs font-bold uppercase tracking-widest flex items-center gap-2 shadow-[0_0_10px_rgba(220,38,38,0.4)]">
                     <Save className="w-4 h-4" /> Save Protocol
                   </button>
                </div>
              </div>
            </div>
          ) : (
            <div className="h-full flex flex-col items-center justify-center text-steel opacity-30">
               <LayoutTemplate className="w-24 h-24 mb-4 stroke-1" />
               <p className="font-mono text-sm uppercase tracking-widest">Select Protocol</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { AppSettings } from '../types';
import { fetchJson } from '../src/lib/http';
import { Save, Settings as SettingsIcon } from 'lucide-react';

export default function Settings() {
  const [settings, setSettings] = useState<AppSettings | null>(null);
  const [msg, setMsg] = useState('');

  useEffect(() => {
    fetchJson<AppSettings>('/api/settings').then(setSettings);
  }, []);

  const save = async () => {
    if (!settings) return;
    await fetchJson('/api/settings', {
        method: 'POST',
        headers: {'Content-Type': 'application/json'},
        body: JSON.stringify(settings)
    });
    setMsg('SAVED');
    setTimeout(() => setMsg(''), 2000);
  };

  if (!settings) return <div className="p-10 text-katana font-mono animate-pulse">LOADING SYSTEM...</div>;

  return (
    <div className="max-w-3xl mx-auto space-y-8 animate-in slide-in-from-bottom-5 duration-500">
      <div className="border-l-4 border-katana pl-4">
        <h2 className="text-3xl font-bold text-white tracking-tight uppercase flex items-center gap-3">
           System Configuration
        </h2>
        <p className="text-steel font-mono text-xs mt-1 tracking-wider">&gt;&gt; GLOBAL PARAMETER ADJUSTMENT</p>
      </div>

      <div className="bg-armor border border-white/10 p-8 relative overflow-hidden">
        <SettingsIcon className="absolute -top-10 -right-10 w-64 h-64 text-white opacity-5 rotate-12" />

        <div className="relative z-10 space-y-10">
            <section>
              <h3 className="text-sm font-bold text-katana uppercase tracking-widest mb-6 border-b border-white/5 pb-2">Core Performance</h3>
              <div className="grid grid-cols-2 gap-8">
                 <div className="space-y-2">
                   <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Concurrency Limit</label>
                   <input 
                      type="number" min="1" max="10"
                      value={settings.concurrency}
                      onChange={e => setSettings({...settings, concurrency: parseInt(e.target.value) || 1})}
                      className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono"
                   />
                 </div>
                 <div className="space-y-2">
                   <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Rate Limit (req/min)</label>
                   <input 
                      type="number" min="1"
                      value={settings.rateLimitPerMinute}
                      onChange={e => setSettings({...settings, rateLimitPerMinute: parseInt(e.target.value) || 10})}
                      className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono"
                   />
                 </div>
              </div>
            </section>

            <section>
               <h3 className="text-sm font-bold text-katana uppercase tracking-widest mb-6 border-b border-white/5 pb-2">Output</h3>
               <div className="space-y-6">
                  <div className="space-y-2">
                    <label className="block text-xs font-bold text-steel uppercase tracking-wider font-mono">Filename Pattern</label>
                    <input 
                        type="text"
                        value={settings.filenamePattern}
                        onChange={e => setSettings({...settings, filenamePattern: e.target.value})}
                        className="w-full bg-plate border border-white/10 p-3 text-white focus:border-katana focus:outline-none font-mono text-sm"
                    />
                    <p className="text-[10px] text-steel font-mono">Variables: &#123;title&#125;</p>
                  </div>
               </div>
            </section>

            <div className="pt-6 flex items-center justify-end gap-4 border-t border-white/5">
               {msg && <span className="text-green-500 font-mono text-xs uppercase tracking-widest animate-pulse">{msg}</span>}
               <button onClick={save} className="bg-katana hover:bg-red-600 text-black px-8 py-3 font-bold uppercase tracking-widest flex items-center gap-2 transition-all shadow-[0_0_15px_rgba(220,38,38,0.5)]">
                 <Save className="w-5 h-5" /> Commit Changes
               </button>
            </div>
        </div>
      </div>
    </div>
  );
}

