import * as cheerio from 'cheerio';
import { chromium } from 'playwright';
import { normalizeHost } from './domain.ts';
import type { ProtocolTemplate, DiagnosticResult, AppSettings } from '../types.ts';

// Standardized cleanup function
function cleanText(text: string): string {
  if (!text) return '';
  // Normalize whitespace, collapse multiple newlines
  let t = text.replace(/\s+/g, ' ').trim(); 
  return t;
}

function postProcessBody(body: string): string {
    return body
        .replace(/\r\n/g, '\n') // CRLF -> LF
        .replace(/\n{3,}/g, '\n\n') // Collapse 3+ newlines
        .trim();
}

export async function fetchHtml(url: string, waitForSelector?: string): Promise<string> {
    // 1. Try basic fetch first (faster)
    try {
        const res = await fetch(url, { 
            headers: { 
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/121.0.0.0 Safari/537.36',
                'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,image/webp,*/*;q=0.8',
                'Accept-Language': 'en-US,en;q=0.5',
            } 
        });

        if (res.status === 403 || res.status === 429 || res.status === 503) {
            throw new Error(`Blocked/RateLimited: ${res.status}`);
        }

        if (!res.ok) throw new Error(`HTTP ${res.status}`);

        const html = await res.text();

        // 2. Validate Static Content
        // If we expect a selector, check if it exists in the static HTML. 
        // If not, it's likely a SPA or protected by JS challenge -> throw to trigger fallback.
        if (waitForSelector) {
            const $ = cheerio.load(html);
            if ($(waitForSelector).length === 0) {
                 // Check if it's a Cloudflare challenge page
                 if (html.includes('Just a moment') || html.includes('Enable JavaScript')) {
                     throw new Error("Cloudflare challenge detected");
                 }
                 throw new Error(`Selector '${waitForSelector}' not found in static response (needs JS?)`);
            }
        }

        return html;

    } catch (e: any) {
        console.log(`Static fetch failed for ${url} (Reason: ${e.message}). Switching to Playwright.`);

        // 3. Playwright Fallback
        const browser = await chromium.launch({ headless: true });
        try {
            const context = await browser.newContext({
                userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/121.0.0.0 Safari/537.36',
                viewport: { width: 1280, height: 720 }
            });

            const page = await context.newPage();

            // Block media to speed up
            await page.route('**/*.{png,jpg,jpeg,gif,webp,svg,woff,woff2}', route => route.abort());

            await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 60000 });

            if (waitForSelector) {
                try { 
                    await page.waitForSelector(waitForSelector, { state: 'attached', timeout: 15000 }); 
                } catch (err) {
                    console.warn(`Playwright timed out waiting for selector: ${waitForSelector}`);
                }
            }

            const content = await page.content();
            return content;
        } catch (pwError: any) {
            throw new Error(`Extraction failed: ${pwError.message}`);
        } finally {
            await browser.close();
        }
    }
}

export function findProtocol(url: string, templates: ProtocolTemplate[]): ProtocolTemplate | undefined {
    const host = normalizeHost(url);
    return templates.find(t => {
        const tHost = normalizeHost(t.domain);
        return host === tHost || host.endsWith('.' + tHost);
    });
}

export async function extract(url: string, templates: ProtocolTemplate[]) {
    const protocol = findProtocol(url, templates);
    const html = await fetchHtml(url, protocol ? protocol.contentSelector : undefined);
    const $ = cheerio.load(html);

    let title = '';
    let body = '';

    if (protocol) {
        // 1. Root
        const $root = $(protocol.contentSelector).first();
        if ($root.length === 0) {
            throw new Error(`Content selector '${protocol.contentSelector}' matched 0 elements.`);
        }

        // 2. Cleanup
        // Standard removals
        $root.find('script, style, iframe, noscript').remove();
        $root.find('div[id^="pf-"]').remove(); // Ad blocks logic per prompt

        // Custom removals
        if (protocol.removeSelectors) {
            protocol.removeSelectors.forEach(sel => $root.find(sel).remove());
        }

        // 3. Title
        const $title = $(protocol.titleSelector).first();
        title = cleanText($title.text());

        // 4. Body Paragraphs
        const paras: string[] = [];
        $root.find('p').each((_, el) => {
            const t = cleanText($(el).text());
            if (t) paras.push(t);
        });

        // 5. Remove dup title
        if (paras.length > 0 && paras[0] === title) {
            paras.shift();
        }

        // Fallback if no P tags
        if (paras.length === 0) {
            const raw = cleanText($root.text());
            // Attempt to remove title from raw text if it starts with it
            if (raw.startsWith(title)) {
                body = raw.substring(title.length).trim();
            } else {
                body = raw;
            }
        } else {
            body = paras.join('\n\n');
        }

    } else {
        // Heuristic / Auto Mode fallback
        const titleEl = $('h1').first();
        title = cleanText(titleEl.text());
        $('script, style, iframe').remove();
        const paras: string[] = [];
        $('p').each((_, el) => {
             const t = cleanText($(el).text());
             if (t && t.length > 20) paras.push(t);
        });
        body = paras.join('\n\n');
        if (!body) throw new Error("No protocol found and auto-extraction failed.");
    }

    return {
        title,
        content: postProcessBody(body),
        url,
        matchedProtocol: protocol?.domain
    };
}

export async function runDiagnostics(
    url: string, 
    domain: string, 
    titleSelector: string, 
    contentSelector: string, 
    removalSelectors: string[] = []
): Promise<DiagnosticResult> {
    // IMPORTANT: Pass contentSelector to fetchHtml so it waits for JS rendering if needed
    const html = await fetchHtml(url, contentSelector);

    const $ = cheerio.load(html);
    const host = normalizeHost(url);

    const $root = $(contentSelector).first();
    const contentMatches = $(contentSelector).length;

    // Virtual cleanup for preview
    const $clone = $root.clone();
    $clone.find('script, style, iframe, noscript').remove();
    $clone.find('div[id^="pf-"]').remove();
    removalSelectors.forEach(s => {
        if(s.trim()) $clone.find(s).remove();
    });

    const $title = $(titleSelector).first();
    const titleMatches = $(titleSelector).length;
    const titleText = cleanText($title.text());

    let pCount = 0;
    const paras: string[] = [];
    $clone.find('p').each((_, el) => {
        const t = cleanText($(el).text());
        if (t) {
            paras.push(t);
            pCount++;
        }
    });

    let bodyPreview = '';
    if (paras.length > 0) {
        if (paras[0] === titleText) paras.shift();
        bodyPreview = paras.join('\n\n');
    } else {
        bodyPreview = cleanText($clone.text());
    }

    return {
        host,
        titleMatches,
        contentMatches,
        paragraphCount: pCount,
        titlePreview: titleText.substring(0, 120),
        contentPreview: bodyPreview.substring(0, 120),
    };
}

import type { BatchItem, BatchStatus } from '../types.ts';
import * as extractor from './extractor.ts';
import * as storage from './storage.ts';
import AdmZip from 'adm-zip';
import sanitize from 'sanitize-filename';
import { Buffer } from 'buffer';

let queue: BatchItem[] = [];
let isProcessing = false;
let activeWorkers = 0;
let shouldStop = false;

// Token bucket for rate limiting
let tokens = 0;
let lastRefill = Date.now();

export function getStatus(): BatchStatus {
    const completed = queue.filter(i => i.status === 'success').length;
    const failed = queue.filter(i => i.status === 'failed').length;
    return {
        queue,
        isProcessing,
        completedCount: completed,
        failedCount: failed,
        totalCount: queue.length
    };
}

export function addItems(urls: string[]) {
    const newItems = urls.map(url => ({
        id: Math.random().toString(36).substring(2, 9),
        url: url.trim(),
        status: 'pending' as const
    }));
    queue.push(...newItems);
}

export function clearQueue() {
    if (!isProcessing) {
        queue = [];
    }
}

export async function startProcessing() {
    if (isProcessing) return;
    shouldStop = false;
    isProcessing = true;

    const settings = await storage.getSettings();
    const maxConcurrency = settings.concurrency || 1;

    // Init tokens
    tokens = settings.rateLimitPerMinute; 
    lastRefill = Date.now();

    // Main loop
    while (!shouldStop) {
        // Refill tokens
        const now = Date.now();
        const elapsed = now - lastRefill;
        if (elapsed > 60000) {
            tokens = settings.rateLimitPerMinute;
            lastRefill = now;
        }

        // Check completion
        const pending = queue.find(i => i.status === 'pending');
        if (!pending && activeWorkers === 0) {
            isProcessing = false;
            break;
        }

        // Spawn worker if allowed
        if (pending && activeWorkers < maxConcurrency && tokens > 0) {
            tokens--;
            activeWorkers++;
            processItem(pending).finally(() => {
                activeWorkers--;
            });
        }

        // Wait a bit before next loop tick
        await new Promise(r => setTimeout(r, 200));
    }

    isProcessing = false;
}

export function stopProcessing() {
    shouldStop = true;
}

async function processItem(item: BatchItem) {
    item.status = 'processing';
    try {
        const templates = await storage.getTemplates();
        const result = await extractor.extract(item.url, templates);
        item.result = result;
        item.status = 'success';
    } catch (e: any) {
        item.status = 'failed';
        item.error = e.message;
        console.error(`Failed ${item.url}:`, e);
    }
}

export async function createBatchZip() {
    const zip = new AdmZip();
    const successItems = queue.filter(i => i.status === 'success' && i.result);

    // Add text files
    successItems.forEach(item => {
        if (item.result) {
            const safeTitle = sanitize(item.result.title).substring(0, 100);
            const content = `${item.result.title}\n\n${item.result.content}`;
            zip.addFile(`${safeTitle}.txt`, Buffer.from(content, 'utf8'));
        }
    });

    // Add manifest
    const manifest = {
        generatedAt: new Date().toISOString(),
        total: successItems.length,
        items: successItems.map(i => ({
            url: i.url,
            title: i.result?.title,
            filename: `${sanitize(i.result?.title || '')}.txt`
        }))
    };
    zip.addFile('manifest.json', Buffer.from(JSON.stringify(manifest, null, 2), 'utf8'));

    return zip.toBuffer();
}

